/* ============================================
 *  translations.js - 장문 콘텐츠 번역 (7개 언어)
 *  한국어 원본 수정 → 다른 언어도 같은 키만 업데이트하면 됨
 *  app.js에서는 L('키', {변수}) 로만 호출
 *
 *  사용법:
 *    L('daily_greeting')
 *    L('daily_card_intro', { card: '마법사', direction: '정방향' })
 *
 *  {placeholder} 문법:
 *    {card}     = 카드 이름
 *    {dir}      = 정방향/역방향
 *    {kw}       = 키워드 (쉼표 구분)
 *    {kw0}~{kw3}= 개별 키워드
 *    {el}       = 원소 이름
 *    {mbti}     = MBTI 유형
 *    {name}     = 사용자 이름
 *    {topic}    = 주제 이름
 *    {year}     = 연도
 * ============================================ */
