  /* ── 기존 I18N 객체에 키를 추가하는 헬퍼 ── */
  function addKeys(langCode, keys) {
    if (!window.I18N) return;
    if (!window.I18N[langCode]) window.I18N[langCode] = {};
    var target = window.I18N[langCode];
    for (var k in keys) {
      if (keys.hasOwnProperty(k)) target[k] = keys[k];
    }
  }

